### 3️⃣ Backend snippets

**`models/Ulama.js`**

```js
const mongoose = require('mongoose');

const ulamaSchema = new mongoose.Schema({
  name: { type: String, required: true },
  subject: String,
  bio: String,
  createdAt: { type: Date, default: Date.now }
});

module.exports = mongoose.model('Ulama', ulamaSchema);
```

**`routes/ulama.js`**

```js
const express = require('express');
const router = express.Router();
const ulamaCtrl = require('../controllers/ulamaController');

router.get('/', ulamaCtrl.list);
router.post('/', ulamaCtrl.create);
router.get('/:id', ulamaCtrl.detail);
router.put('/:id', ulamaCtrl.update);
router.delete('/:id', ulamaCtrl.delete);

module.exports = router;
```

**`controllers/ulamaController.js`**

```js
const Ulama = require('../models/Ulama');

exports.list = async (req, res) => {
  const ulamas = await Ulama.find();
  res.json(ulamas);
};

exports.create = async (req, res) => {
  const ulama = new Ulama(req.body);
  await ulama.save();
  res.status(201).json(ulama);
};

// …detail, update, delete similar
```

**`app.js`**

```js
const express = require('express');
const mongoose = require('mongoose');
const ulamaRoutes = require('./routes/ulama');

const app = express();
app.use(express.json());

mongoose.connect('mongodb://localhost:27017/ulama', { useNewUrlParser: true });

app.use('/api/ulama', ulamaRoutes);

app.listen(5000, () => console.log('Server running on 5000'));
```

---

### 4️⃣ Frontend (React) basics

**`api/ulama.js`**

```js
import axios from 'axios';
const API = 'http://localhost:5000/api/ulama';

export const getUlamas = () => axios.get(API);
export const createUlama = data => axios.post(API, data);
// …etc
```

**`components/UlamaList.jsx`**

```jsx
import { useEffect, useState } from 'react';
import { getUlamas } from '../api/ulama';

export default function UlamaList() {
  const [ulamas, setUlamas] = useState([]);

  useEffect(() => {
    getUlamas().then(r => setUlamas(r.data));
  }, []);

  return (
    <ul>
      {ulamas.map(u => <li key={u._id}>{u.name}</li>)}
    </ul>
  );
}
```

---

### 5️⃣ Run it

```bash
# Backend
cd backend
npm install
node app.js

# Frontend
cd ../frontend
npm install
npm start
```

That’s a bare‑bones “Ulama” app. Add auth, pagination, styling, etc. as you go. Happy coding!
